import { useState } from 'react';
import { apiService } from '../services/api';




const Deposit = () => {

    const [formData, setFormData] = useState({
        accountNumber: '',
        amount: '',
        description: ''
    });


    const [recentTransactions, setRecentTransactions] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [searchLoading, setSearchLoading] = useState(false);
    const [accountInfo, setAccountInfo] = useState(null);



    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };



    // const searchAccount = async () => {
    //     if (!formData.accountNumber.trim()) {
    //         setError('Please enter an account number');
    //         return;
    //     }

    //     setSearchLoading(true);
    //     setError('');
    //     setAccountInfo(null);

    //     try {

    //         const response = await apiService.findAccountByAccountNumber(formData.accountNumber);
    //         const account = response.data || [];

    //         if (account.accountNumber) {
    //             setAccountInfo(account);
    //             setSuccess(`Account found: ${account.accountType} Account - ${account.accountNumber}`);
    //             //fetch recent transactions
    //             fetchRecentTransactions(account.accountNumber);
    //         } else {
    //             setError(response.error);
    //         }
    //     } catch (error) {
    //         setError('Error searching for account' + error);
    //         console.error('Account search error:', error);
    //     } finally {
    //         setSearchLoading(false);
    //     }
    // };

    const searchAccount = async () => {
    const accountNumber = formData.accountNumber.trim(); // ✅ clean input

    if (!accountNumber) {
        setError('Please enter an account number');
        return;
    }

    setSearchLoading(true);
    setError('');
    setAccountInfo(null);
    setSuccess('');

    try {
        const response = await apiService.findAccountByAccountNumber(accountNumber);
        const account = response.data;

        if (account && account.accountNumber) {
            setAccountInfo(account);
            setSuccess(`Account found: ${account.accountType} Account - ${account.accountNumber}`);

            // ✅ pass correct account number directly
            fetchRecentTransactions(account.accountNumber);

        } else {
            setError(response.error || 'Account not found');
        }

    } catch (error) {
        console.error('Account search error:', error.response?.data || error);
        setError('Error searching for account');
    } finally {
        setSearchLoading(false);
    }
};



    // const fetchRecentTransactions = async () => {
    //     try {
    //         if (formData.accountNumber) {
    //             const response = await apiService.getTransactions(formData.accountNumber, 0, 3);
    //             if (response.data.statusCode === 200) {
    //                 setRecentTransactions(response.data.data || []);
    //             }
    //         }
    //     } catch (error) {
    //         console.error('Error fetching recent transactions:', error);
    //     }
    // };

    //chatgpt

    const fetchRecentTransactions = async (accNo) => {
    try {
        const accountNumber = accNo?.trim();

        console.log("Sending accountNumber:", accountNumber);

        const response = await apiService.getTransactions(accountNumber, 0, 3);

        if (response.data.statusCode === 200) {
            setRecentTransactions(response.data.data || []);
        }

    } catch (error) {
        console.error('Transactions error:', error.response?.data);

        if (error.response?.status === 400) {
            setRecentTransactions([]); // fallback
        }
    }
};


    const formatCurrency = (amount, currency = 'RUPEES') => {
    const currencyMap = {
        RUPEES: 'INR',
        USD: 'USD',
        EUR: 'EUR',
        NGN: 'NGN'
    };

    const mappedCurrency = currencyMap[currency] || currency;

    try {
        return new Intl.NumberFormat('en-IN', {
            style: 'currency',
            currency: mappedCurrency
        }).format(amount);
    } catch {
        return `₹${amount}`;
    }
};

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleString();
    };




    const handleSubmit = async (e) => {

        e.preventDefault();
        setLoading(true);
        setError('');
        setSuccess('');

        // Validation
        if (!formData.accountNumber.trim()) {
            setError('Account number is required');
            setLoading(false);
            return;
        }

        if (!formData.amount || parseFloat(formData.amount) <= 0) {
            setError('Please enter a valid amount greater than 0');
            setLoading(false);
            return;
        }

        if (!formData.description.trim()) {
            setError('Description is required');
            setLoading(false);
            return;
        }

        try {
            const depositData = {
                transactionType: 'DEPOSIT',
                amount: parseFloat(formData.amount),
                accountNumber: formData.accountNumber,
                description: formData.description
            };

            const response = await apiService.makeDeposit(depositData);

            if (response.data.statusCode === 200) {
                setSuccess(`Successfully deposited $${formData.amount} to account ${formData.accountNumber}`);

                // Reset form
                setFormData({
                    accountNumber: formData.accountNumber, // Keep account number for multiple deposits
                    amount: '',
                    description: ''
                });

                // Refresh recent transactions
                fetchRecentTransactions();

                // Clear success message after 5 seconds
                setTimeout(() => {
                    setSuccess('');
                }, 5000);
            } else {
                setError(response.data.message || 'Deposit failed');
            }
        } catch (error) {
            setError(error.response?.data?.message || 'An error occurred during deposit');
        } finally {
            setLoading(false);
        }
    };





    return (
        <div className="admin-deposit-container">
            <div className="admin-deposit-header">
                <h2>Deposit funds into customer accounts</h2>
            </div>

            {error && <div className="error-message">{error}</div>}
            {success && <div className="success-message">{success}</div>}

            <div className="deposit-content">
                <div className="deposit-form-section">
                    <div className="form-card">
                        <h2>Make Deposit</h2>

                        <form onSubmit={handleSubmit}>
                            <div className="form-group">
                                <label htmlFor="accountNumber">Account Number *</label>
                                <div className="input-with-button">
                                    <input
                                        type="text"
                                        id="accountNumber"
                                        name="accountNumber"
                                        value={formData.accountNumber}
                                        onChange={handleChange}
                                        placeholder="Enter customer account number"
                                        required
                                    />
                                    <button
                                        type="button"
                                        className="btn btn-secondary"
                                        onClick={searchAccount}
                                        disabled={searchLoading}
                                    >
                                        {searchLoading ? 'Searching...' : 'Verify'}
                                    </button>
                                </div>
                            </div>

                            {accountInfo && (
                                <div className="account-info">
                                    <h4>Account Information</h4>
                                    <div className="account-details">
                                        <p><strong>Type:</strong> {accountInfo.accountType}</p>
                                        <p><strong>Balance:</strong> {formatCurrency(accountInfo.balance, accountInfo.currency)}</p>
                                        <p><strong>Status:</strong> <span className={`status ${accountInfo.accountStatus.toLowerCase()}`}>{accountInfo.accountStatus}</span></p>
                                    </div>
                                </div>
                            )}

                            <div className="form-group">
                                <label htmlFor="amount">Amount *</label>
                                <input
                                    type="number"
                                    id="amount"
                                    name="amount"
                                    value={formData.amount}
                                    onChange={handleChange}
                                    placeholder="0.00"
                                    min="0.01"
                                    step="0.01"
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label htmlFor="description">Description *</label>
                                <input
                                    type="text"
                                    id="description"
                                    name="description"
                                    value={formData.description}
                                    onChange={handleChange}
                                    placeholder="e.g., Cash deposit, Transfer from bank, etc."
                                    required
                                />
                            </div>

                            <button
                                type="submit"
                                className="btn btn-primary deposit-btn"
                                disabled={loading || !accountInfo}
                            >
                                {loading ? 'Processing Deposit...' : 'Deposit Funds'}
                            </button>
                        </form>
                    </div>
                </div>

                <div className="recent-transactions-section">
                    <div className="transactions-card">
                        <h2>Recent Deposits</h2>
                        {recentTransactions.length > 0 ? (
                            <div className="transactions-list">
                                {recentTransactions
                                    .filter(tx => tx.transactionType === 'DEPOSIT')
                                    .slice(0, 5)
                                    .map(transaction => (
                                        <div key={transaction.id} className="transaction-item">
                                            <div className="transaction-main">
                                                <div className="transaction-type deposit">DEPOSIT</div>
                                                <div className="transaction-amount">
                                                    +{formatCurrency(transaction.amount)}
                                                </div>
                                            </div>
                                            <div className="transaction-details">
                                                <div className="transaction-date">
                                                    {formatDate(transaction.transactionDate)}
                                                </div>
                                                <div className="transaction-description">
                                                    {transaction.description}
                                                </div>
                                                <div className="transaction-account">
                                                    Account: {transaction.sourceAccount || formData.accountNumber}
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                            </div>
                        ) : (
                            <div className="no-transactions">
                                <p>No recent deposits found</p>
                                <p className="hint">Recent deposits will appear here after transactions</p>
                            </div>
                        )}
                    </div>

                    <div className="guidelines-card">
                        <h3>Deposit Guidelines</h3>
                        <ul>
                            <li>Verify account number before processing deposits</li>
                            <li>Ensure amount is correct and properly formatted</li>
                            <li>Provide clear description for audit purposes</li>
                            <li>Double-check all information before submitting</li>
                            <li>Keep records of all deposit transactions</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    );

}

export default Deposit;
